  Purpose: singleton SapClient init from env, reused across routes and services.

  import { Connection, Keypair } from '@solana/web3.js';
  import { AnchorProvider, Wallet } from '@coral-xyz/anchor';
  import { SapClient } from '@oobe-protocol-labs/synapse-sap-sdk';

  let _client: SapClient | null = null;

  export function getSapClient(): SapClient {
    if (_client) return _client;
    const secretKey = process.env.SAP_WALLET_SECRET_KEY;
    if (!secretKey) throw new Error('SAP_WALLET_SECRET_KEY not set');
    // Support both base58 and comma-separated byte arrays
    const kp = secretKey.includes(',') 
      ? Keypair.fromSecretKey(Uint8Array.from(secretKey.split(',').map(Number)))
      : Keypair.fromSecretKey(Buffer.from(secretKey, 'base64')); // or bs58 decode if installed
    const connection = new Connection(process.env.SAP_RPC_URL || 'https://api.mainnet-beta.solana.com', 'confirmed');
    const anchorWallet = new Wallet(kp);
    const provider = new AnchorProvider(connection, anchorWallet, { commitment: 'confirmed' });
    _client = SapClient.from(provider);
    return _client;
  }

  NOTE: Check SapClient import path from the actual installed package. May be:
    import { SapClient } from '@oobe-protocol-labs/synapse-sap-sdk';
    or import { SapClient } from '@oobe-protocol-labs/synapse-sap-sdk/src/client';
  Run: node -e "console.log(Object.keys(require('@oobe-protocol-labs/synapse-sap-sdk')))" after installing to confirm.

